// Build a weekly campaign performance report
const campaigns = $input.all();

const reportLines = [
  '📊 *Aegis Marketing Cloud — Weekly Campaign Report*',
  `📅 *Week of:* ${new Date().toLocaleDateString('en-US', { month: 'long', day: 'numeric', year: 'numeric' })}`,
  '',
  '━━━━━━━━━━━━━━━━━━━━━━━━━━',
  '',
];

let totalSent = 0;
let totalDelivered = 0;
let totalOpened = 0;
let totalClicked = 0;
let totalBounced = 0;
let totalComplained = 0;
let campaignCount = 0;

for (const item of campaigns) {
  const campaign = item.json.data || item.json;
  const name = campaign.name || campaign.campaign_name || 'Untitled Campaign';
  const sent = campaign.total_recipients || campaign.sent_count || 0;
  const delivered = campaign.delivered_count || 0;
  const opened = campaign.opened_count || 0;
  const clicked = campaign.clicked_count || 0;
  const bounced = campaign.bounced_count || 0;
  const complained = campaign.complained_count || 0;
  const status = campaign.status || 'completed';

  totalSent += sent;
  totalDelivered += delivered;
  totalOpened += opened;
  totalClicked += clicked;
  totalBounced += bounced;
  totalComplained += complained;
  campaignCount++;

  const openRate = delivered > 0 ? ((opened / delivered) * 100).toFixed(1) : '0.0';
  const clickRate = delivered > 0 ? ((clicked / delivered) * 100).toFixed(1) : '0.0';
  const bounceRate = sent > 0 ? ((bounced / sent) * 100).toFixed(1) : '0.0';

  reportLines.push(
    `📧 *${name}* (${status})`,
    `   • Sent: ${sent}  |  Delivered: ${delivered}`,
    `   • Opens: ${opened} (${openRate}%)  |  Clicks: ${clicked} (${clickRate}%)`,
    `   • Bounces: ${bounced} (${bounceRate}%)  |  Complaints: ${complained}`,
    ''
  );
}

// Summary row
const overallOpenRate = totalDelivered > 0 ? ((totalOpened / totalDelivered) * 100).toFixed(1) : '0.0';
const overallClickRate = totalDelivered > 0 ? ((totalClicked / totalDelivered) * 100).toFixed(1) : '0.0';

reportLines.push(
  '━━━━━━━━━━━━━━━━━━━━━━━━━━',
  `*📈 Summary (${campaignCount} campaigns)*`,
  `   • Total Sent: ${totalSent}`,
  `   • Total Delivered: ${totalDelivered}`,
  `   • Overall Open Rate: ${overallOpenRate}%`,
  `   • Overall Click Rate: ${overallClickRate}%`,
  `   • Total Bounces: ${totalBounced}`,
  `   • Total Complaints: ${totalComplained}`,
  '',
  `🤖 *Generated by:* Aegis n8n Workflow — campaign-report.json`
);

return [{
  json: {
    blocks: [
      {
        type: 'section',
        text: {
          type: 'mrkdwn',
          text: reportLines.join('\n'),
        },
      },
    ],
  },
}];
